#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}

template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline void chkmax(T&x,const T&y){x<y?x=y:T();}
template<typename T> inline void chkmin(T&x,const T&y){y<x?x=y:T();}
const int INF=0x3f3f3f3f,Mod=998244353;
int w[25][25],dp[1<<23],K,idx[1<<23],tmp[2][1352080][23],f1[1<<23],f2[1<<23];int n;
int OP[20000010],*op[25],*Op=OP,len[25];
int fac[30],ifac[30];inline int qpow(int a,int b=Mod-2){int r(1);while(b)b&1?r=1ll*r*a%Mod:0,a=1ll*a*a%Mod,b=b>>1;return r;}
inline int C(int n,int m){return 1ll*fac[n]*ifac[m]%Mod*ifac[n-m]%Mod;}

//inline void print(int x){for(int i=0;i<n;++i)if((x>>i)&1)putchar('1');else putchar('0');}
//inline void debug(){for(int S=0;S<(1<<n);++S){print(S);printf(" : %d\n",dp[S]);}}

int main()
{
	fac[0]=fac[1]=ifac[0]=ifac[1]=1;
	rep(1,25,i)fac[i]=1ll*fac[i-1]*i%Mod,ifac[i]=qpow(fac[i]);
	int TT=read();n=read();K=read();int lst=read()-1;
	while(--TT){int x=read()-1;if(lst!=x)++w[lst][x],lst=x;}
	rep(1,n,i){op[i]=Op;Op+=C(n,i);}
	for(int S=1;S<(1<<n);++S)
	{
		f1[S]=f2[S]=-1;int pcnt=__builtin_popcount(S);
		op[pcnt][idx[S]=(len[pcnt]++)]=S;
		for(int i=0;i<n;++i)if((S>>i)&1){if(~f1[S]){f2[S]=i;break;}f1[S]=i;}
		int IDX=0;for(int i=0;i<n;++i)if((S>>i)&1){dp[S]=dp[S^(1<<i)];IDX=i;break;}
		for(int i=0;i<n;++i)dp[S]+=(S>>i)&1?-w[i][IDX]:w[IDX][i];
		
	}
	for(int T=0;T<n;++T)
	{
		int S=(1<<T),i=0;for(int j=0;j<n;++j)if((S>>j)&1){i=j;break;}
		for(int j=0;j<n;++j)tmp[1][idx[S]][i]+=w[j][i];
		dp[S]+=K*tmp[1][idx[S]][i];
//		printf("tmp[%d][%d] = %d\n",S,i,tmp[1][idx[S]][i]);
	}
//	debug();
	rep(2,n,L)
	{
		int I=L&1;memset(tmp[I],0,sizeof(tmp[I]));
		for(int i=0;i<len[L];++i)
		{
			int S=op[L][i],pcnt=__builtin_popcount(S);
			tmp[I][i][f1[S]]=tmp[I^1][idx[S^(1<<f2[S])]][f1[S]]-w[f2[S]][f1[S]]+w[f1[S]][f2[S]];
			for(int j=f1[S]+1;j<n;++j)if((S>>j)&1){tmp[I][i][j]=tmp[I^1][idx[S^(1<<f1[S])]][j]-w[f1[S]][j]+w[j][f1[S]];}
			int mn=INF;for(int j=0;j<n;++j)if((S>>j)&1)
			{
				chkmin(mn,dp[S^(1<<j)]+K*tmp[I][i][j]*pcnt);
//				printf("tmp[%d][%d] = %d\n",S,j,tmp[I][i][j]);
//				printf("%d -> %d\n",S^(1<<j),S);
			}
//			printf("%d :: %d\n",S,mn);
			dp[S]+=mn;
		}
	}
//	debug();
	printf("%d\n",dp[(1<<n)-1]);return 0;
}
